const raw = $json?.content?.[0]?.text?.trim() || '{}';
const text = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
let teams = { home_team: 'football', away_team: 'match' };
try {
  const parsed = JSON.parse(text);
  if (parsed.home_team) teams.home_team = parsed.home_team;
  if (parsed.away_team) teams.away_team = parsed.away_team;
} catch(e) {}
return [{ json: teams }];

