parameters.jsCode:
const bgData = $('Extract Background URL').first().json;
const claudeResp = $input.first().json;
const translated = claudeResp?.content?.[0]?.text?.trim();
return [{ json: { ...bgData, text_narration_full: translated || bgData.text_narration_full } }];

const showText = $('Form: Video Request').item.json.text !== 'Hide text';
const dur = $json.heygen_duration;
const heygenUrl = $json.heygen_video_url;
const pexelsUrl = $json.pexels_url;

const captionTrack = {
  clips: [{
    asset: {
      type: 'caption',
      src: 'alias://speech',
      font: { family: 'Montserrat ExtraBold', color: '#FFFF00', size: 32, lineHeight: 1.05 },
      margin: { top: 0.62, left: 0.04, right: 0.55 }
    },
    start: 0,
    length: dur
  }]
};

const heygenTrack = {
  clips: [{
    asset: { type: 'video', src: heygenUrl, chromaKey: { color: '#5cb81a', threshold: 128, halo: 128 } },
    alias: 'speech',
    start: 0,
    length: dur,
    scale: 0.9,
    offset: { x: 0.18, y: -0.34 }
  }]
};

const pexelsTrack = {
  clips: [{
    asset: { type: 'video', src: pexelsUrl, volume: 0 },
    start: 0,
    length: dur,
    fit: 'cover',
    effect: 'zoomIn'
  }]
};

const tracks = showText ? [captionTrack, heygenTrack, pexelsTrack] : [heygenTrack, pexelsTrack];

return [{ json: { ...$input.first().json, shotstack_tracks: tracks } }];

